#include<bits/stdc++.h>
using namespace std;
unsigned long long n,a[10],b[10];
int main(){
	int cnt=0;
	cin>>n;
	while(n!=495){
		int m=1;
		for(int j=1;j<=3;j++){
			a[j]=n/m%10;
			b[j]=n/m%10;
			m=m*10;
		}
		sort(a+1,a+4);
		sort(b+1,b+4,greater<int>());
		for(int i=1;i<=1;i++){
			long long x=a[i]*100+a[i+1]*10+a[i+2],y=b[i]*100+b[i+1]*10+b[i+2];
			n=y-x;
		}
		cnt++;	
	}
	cout<<cnt;
	return 0; 
}
